/* VuGen Script Structure */

vuser_init()
{
    // Establish DB connection or login
    lr_start_transaction("login");
    web_submit_data("login.pl", ...);
    lr_end_transaction("login", LR_AUTO);
    return 0;
}

Action()
{
    // Search for flights (Iterates multiple times based on Run Logic)
    lr_start_transaction("search_flight");
    web_url("Search", ...);
    lr_think_time(10);
    lr_end_transaction("search_flight", LR_AUTO);
    return 0;
}

vuser_end()
{
    // Logout and close connections
    lr_start_transaction("logout");
    web_url("Logout", ...);
    lr_end_transaction("logout", LR_AUTO);
    return 0;
}
